import{_ as s,o as t,c as i,a2 as o}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Setup & RGPD","description":"","frontmatter":{"title":"Setup & RGPD"},"headers":[],"relativePath":"docs/fr/publishers/co-branded-contest/setup-guide.md","filePath":"docs/fr/publishers/co-branded-contest/setup-guide.md"}'),r={name:"docs/fr/publishers/co-branded-contest/setup-guide.md"};function n(a,e,l,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[o(`<h1 id="guide-de-mise-en-place" tabindex="-1">Guide de mise en place <a class="header-anchor" href="#guide-de-mise-en-place" aria-label="Permalink to &quot;Guide de mise en place&quot;">​</a></h1><p>Les étapes techniques et juridiques pour lancer un jeu concours co-brandé conforme.</p><hr><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Création de la Landing Page (LP)</h3><p>Vous êtes responsable de l&#39;hébergement du jeu pour rassurer votre client.</p><ul><li><strong>URL :</strong> Sur votre domaine (ex: <code>votre-site.com/jeu-concours-marque</code>).</li><li><strong>Design :</strong> Co-brandé (Votre header habituel + l&#39;univers visuel de l&#39;Annonceur).</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Le Formulaire &amp; RGPD (Critique)</h3><p>Pour monétiser la donnée (vendre le lead à l&#39;annonceur), le formulaire doit respecter strictement le RGPD.</p><div class="danger custom-block"><p class="custom-block-title">Mention obligatoire — case non pré-cochée</p><p>☐ <em>J&#39;accepte de recevoir les offres commerciales du partenaire [Nom de l&#39;Annonceur].</em></p><p>⚠️ Cette case ne doit <strong>JAMAIS</strong> être pré-cochée.</p></div><pre><code>&lt;p&gt;&lt;em&gt;Note : Seuls les participants cochant cette case seront facturés à l&#39;Annonceur. Les autres jouent mais ne sont pas monétisables.&lt;/em&gt;&lt;/p&gt;
</code></pre></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Plan d&#39;activation</h3><p>Pour garantir le volume de leads (et donc vos revenus), activez vos leviers puissants :</p><ul><li><strong>📧 Newsletter dédiée :</strong> &quot;Tentez de gagner XXX€ chez [Marque]&quot;.</li><li><strong>🔔 Web Push Notification.</strong></li><li><strong>🖼️ Bannières Home Page.</strong></li></ul></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Transfert des données</h3><p>À la clôture du jeu :</p><ol><li>Exportez la liste des participants <strong>avec l&#39;opt-in partenaire</strong> (CSV/Excel).</li><li>Transmettez le fichier de manière sécurisée à l&#39;Annonceur (via getinside).</li></ol><div class="tip custom-block"><p class="custom-block-title">Votre travail s&#39;arrête ici</p><p>Une fois le fichier transmis, l&#39;annonceur intègre les leads dans son CRM et envoie <strong>immédiatement</strong> l&#39;email de bienvenue avec le code promo de consolation promis. La rapidité est clé pour maximiser les ventes.</p></div></div></div>`,7)])])}const v=s(r,[["render",n]]);export{m as __pageData,v as default};
